import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('MentorScene')
export class MentorScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    findMentorBtn: Button = null;
    
    @property(Button)
    findStudentBtn: Button = null;
    
    @property(Node)
    myMentorPanel: Node = null;
    
    @property(Node)
    myStudentsPanel: Node = null;
    
    @property(Label)
    mentorNameLabel: Label = null;
    
    @property(Label)
    mentorLevelLabel: Label = null;
    
    @property(ScrollView)
    studentListScrollView: ScrollView = null;
    
    @property(Node)
    studentItemPrefab: Node = null;
    
    @property(Label)
    maxStudentsLabel: Label = null;
    
    private hasMentor = false;
    private mentor = { name: '', level: 0 };
    private students = [
        { id: 1, name: '小财神', level: 15, progress: 60 },
        { id: 2, name: '招财猫', level: 22, progress: 85 }
    ];
    private maxStudents = 4; // 根据等级决定
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.findMentorBtn.node.on(Button.EventType.CLICK, this.onFindMentor, this);
        this.findStudentBtn.node.on(Button.EventType.CLICK, this.onFindStudent, this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        if (this.hasMentor) {
            this.myMentorPanel.active = true;
            this.findMentorBtn.node.active = false;
            this.mentorNameLabel.string = `师父: ${this.mentor.name}`;
            this.mentorLevelLabel.string = `等级: ${this.mentor.level}`;
        } else {
            this.myMentorPanel.active = false;
            this.findMentorBtn.node.active = true;
        }
        
        this.updateStudentList();
        this.maxStudentsLabel.string = `徒弟: ${this.students.length}/${this.maxStudents}`;
    }
    
    updateStudentList() {
        const content = this.studentListScrollView.content;
        content.removeAllChildren();
        
        for (const student of this.students) {
            const node = instantiate(this.studentItemPrefab);
            
            node.getChildByName('NameLabel').getComponent(Label).string = student.name;
            node.getChildByName('LevelLabel').getComponent(Label).string = `Lv.${student.level}`;
            node.getChildByName('ProgressBar').getComponent(ProgressBar).progress = student.progress / 100;
            node.getChildByName('ProgressLabel').getComponent(Label).string = `出师进度: ${student.progress}%`;
            
            // 传功按钮
            const teachBtn = node.getChildByName('TeachBtn').getComponent(Button);
            teachBtn.node.on(Button.EventType.CLICK, () => this.onTeach(student), this);
            
            content.addChild(node);
        }
    }
    
    onFindMentor() {
        // 寻找师父
        const mentors = [
            { name: '财神爷爷', level: 88 },
            { name: '金身罗汉', level: 75 },
            { name: '不败战神', level: 82 }
        ];
        
        const selected = mentors[Math.floor(Math.random() * mentors.length)];
        this.mentor = selected;
        this.hasMentor = true;
        
        alert(`拜${selected.name}为师！`);
        this.updateUI();
    }
    
    onFindStudent() {
        if (this.students.length >= this.maxStudents) {
            alert('徒弟已满');
            return;
        }
        
        // 寻找徒弟
        const newStudent = {
            id: Date.now(),
            name: '新徒弟' + (this.students.length + 1),
            level: Math.floor(Math.random() * 20) + 5,
            progress: 0
        };
        
        this.students.push(newStudent);
        alert(`收${newStudent.name}为徒！`);
        this.updateUI();
    }
    
    onTeach(student: any) {
        // 传功
        student.progress = Math.min(100, student.progress + 10);
        
        if (student.progress >= 100) {
            // 出师
            alert(`${student.name}已出师！获得奖励`);
            GameManager.getInstance().playerData.addCurrency('merit', 100);
            
            // 移除徒弟
            const index = this.students.indexOf(student);
            if (index > -1) {
                this.students.splice(index, 1);
            }
        } else {
            alert(`传功成功！${student.name}进度+10%`);
        }
        
        this.updateUI();
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
